// lib/dashboard/api_client.dart (atualizado)
import 'dart:convert';
import 'package:http/http.dart' as http;
import 'models.dart';


class DashboardApiClient {
final String baseUrl; // ex: https://.../boletobancos
final int empresaId;
final int? parceiroId;
DashboardApiClient(this.baseUrl, {required this.empresaId, this.parceiroId});


Map<String, String> _qp([Map<String, String>? extra]){
final m = {
'empresaId': empresaId.toString(),
if (parceiroId != null) 'parceiroId': parceiroId.toString(),
};
if (extra != null) m.addAll(extra);
return m;
}


Future<List<FinancePoint>> fetchFinanceSeries({int months = 6}) async {
final uri = Uri.parse('$baseUrl/api/dashboard/finance/series')
.replace(queryParameters: _qp({'months': months.toString()}));
final res = await http.get(uri);
if (res.statusCode != 200) throw Exception('Finance series error ${res.statusCode}');
final data = jsonDecode(res.body) as List;
return data.map((e) => FinancePoint(
e['month'] as String,
(e['receivable'] as num).toDouble(),
(e['payable'] as num).toDouble(),
)).toList();
}


Future<TicketStatusCounts> fetchTicketStatusCounts() async {
final uri = Uri.parse('$baseUrl/api/dashboard/tickets/statusCounts')
.replace(queryParameters: _qp());
final res = await http.get(uri);
if (res.statusCode != 200) throw Exception('Tickets error ${res.statusCode}');
final e = jsonDecode(res.body);
return TicketStatusCounts(open: e['open'], inProgress: e['inProgress'], closed: e['closed']);
}


Future<List<ChatsDailyPoint>> fetchChatsDaily({int days = 7}) async {
final uri = Uri.parse('$baseUrl/api/dashboard/chats/daily')
.replace(queryParameters: _qp({'days': days.toString()}));
final res = await http.get(uri);
if (res.statusCode != 200) throw Exception('Chats daily error ${res.statusCode}');
final data = jsonDecode(res.body) as List;
return data.map((e) => ChatsDailyPoint(DateTime.parse(e['date']), e['openChats'] as int)).toList();
}
}
